class Solution {
    public int findMaxK(int[] nums) {
        Map<Integer, Integer> map = new HashMap<>();
        int max = -1;
        for (int num : nums) {
            if (map.containsKey(-num)) {
                max = Math.max(max, num);
                map.put(num, map.getOrDefault(num, 0) + 1);
            } else {
                map.put(num, 1);
            }
        }
        return max;
    }
}
```

